/**
 * @fileoverview Badge component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, ARIA attrs, default config
 *   helpers.js   — count formatting, content resolution
 *   state.js     — reactive state wiring
 *   view.js      — DOM setup / teardown + SM effects
 *   events.js    — (minimal — Badge is display-only)
 *
 * @module module/Badge
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { BadgeDef as DEF } from '../Badge.def.js';

import { DEFAULTS }                          from './constants.js';
import { resolveContent, formatCount }       from './helpers.js';
import { BADGE_TRANSITIONS, createReactiveState } from './state.js';
import { SM_EFFECTS, setupDOM, cleanupDOM }  from './view.js';
import { emitEvent }                         from '../shared/emitEvent.js';

/**
 * Badge — inline status label / counter component (JIT-compatible)
 *
 * Features:
 *   - Five variants: default, success, warning, error, info
 *   - Three sizes: sm, md (default), lg
 *   - Dot indicator mode (no text)
 *   - Count badge with max truncation (99+)
 *   - Pill shape
 *   - Show/hide with animation
 *   - Programmatic API: getControl()
 *
 * @param {string|Element} selector — CSS selector or Element
 * @param {object}   [config]
 * @param {string}   [config.variant]  — 'default'|'success'|'warning'|'error'|'info'
 * @param {string}   [config.size]     — 'sm'|'md'|'lg'
 * @param {boolean}  [config.pill]     — pill shape
 * @param {boolean}  [config.dot]      — dot indicator mode
 * @param {number}   [config.count]    — numeric count
 * @param {number}   [config.max]      — max count display (99+)
 * @param {string}   [config.text]     — text content
 * @param {boolean}  [config.hidden]   — initially hidden
 * @param {function} [config.onChange]  — (value) => void
 */
const Badge = class {
    #root       = null;
    #destroyed = false;
    #contentEl  = null;
    #sm         = null;
    #config     = {};
    #stateRef   = null;
    #setState   = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Badge: element not found \u2192', selector);
            return;
        }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#init();
    }

    #init() {
        const root   = this.#root;
        const config = this.#config;

        // 1. View: build DOM structure
        const { contentEl } = setupDOM(root, config);
        this.#contentEl = contentEl;

        // 2. State machine
        const smConfig = { ...BADGE_TRANSITIONS, effects: SM_EFFECTS };
        const sm = new StateMachine(smConfig, { root });
        this.#sm = sm;

        // 3. Reactive state
        const { ref, setState } = createReactiveState(razyui.state);
        this.#stateRef = ref;
        this.#setState = setState;
        setState({
            count: config.count,
            text: config.text,
            hidden: config.hidden,
        });

        // 4. Initial content
        this.#updateContent();

        // 5. Initial visibility
        if (config.hidden) {
            sm.send('HIDE');
        }
    }

    #updateContent() {
        const { mode, display } = resolveContent(this.#config);
        if (this.#contentEl && mode !== 'dot') {
            this.#contentEl[0].textContent = display;
        }
    }

    // ── Public API ──

    /** Get current count value. */
    get count() {
        return this.#config.count;
    }

    /** Set count value. */
    set count(value) {
        this.#config.count = value;
        this.#config.dot = false;
        this.#setState({ count: value });
        this.#updateContent();
        emitEvent(this.#root[0], 'change', { value, count: value });
        this.#config.onChange?.call(this, value);
    }

    /** Get/set text content. */
    get text() {
        return this.#config.text;
    }

    set text(value) {
        this.#config.text = value;
        this.#config.dot = false;
        this.#config.count = null;
        this.#setState({ text: value });
        this.#updateContent();
    }

    /** Show the badge. */
    show() {
        if (this.#sm.current === 'hidden') {
            this.#sm.send('SHOW');
            this.#setState({ hidden: false });
        }
    }

    /** Hide the badge. */
    hide() {
        if (this.#sm.current === 'visible') {
            this.#sm.send('HIDE');
            this.#setState({ hidden: true });
        }
    }

    /** Toggle visibility. */
    toggle() {
        if (this.#sm.current === 'visible') {
            this.hide();
        } else {
            this.show();
        }
    }

    /** Get current visibility. */
    get visible() {
        return this.#sm.current === 'visible';
    }

    /**
     * Get a reactive control object.
     * @returns {object}
     */
    getControl() {
        const self = this;
        return {
            get count() { return self.count; },
            set count(v) { self.count = v; },
            get text() { return self.text; },
            set text(v) { self.text = v; },
            get visible() { return self.visible; },
            get max() { return self.#config.max; },
            set max(v) { self.#config.max = Number(v); self.count = self.count; },
            get hidden() { return !self.visible; },
            set hidden(v) { v ? self.hide() : self.show(); },
            show:    () => self.show(),
            hide:    () => self.hide(),
            toggle:  () => self.toggle(),
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Cleanup. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        cleanupDOM(this.#root);
        this.#sm = null;
    }
};

export default Badge;
