/**
 * @fileoverview Badge helpers — pure utility functions.
 * @module module/Badge/helpers
 */

/**
 * Format count display value with max truncation.
 *
 * @param {number|null} count — the badge count
 * @param {number} max — maximum display value (e.g. 99)
 * @returns {string} formatted display string
 */
export function formatCount(count, max) {
    if (count == null) return '';
    const num = parseInt(count, 10);
    if (isNaN(num)) return '';
    if (num <= 0) return '';
    return num > max ? `${max}+` : `${num}`;
}

/**
 * Resolve content to display inside the badge.
 *
 * @param {object} config — { dot, count, max, text }
 * @returns {{ mode: string, display: string }}
 */
export function resolveContent(config) {
    const { dot, count, max, text } = config;
    if (dot) return { mode: 'dot', display: '' };
    if (count != null) {
        const display = formatCount(count, max);
        return { mode: 'count', display };
    }
    return { mode: 'label', display: text || '' };
}
