/**
 * @fileoverview Badge component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slots,
 * event handler abstractions, and Custom Element metadata.
 *
 * @module module/Badge.def
 */

import { PART } from './Badge/constants.js';

/**
 * Definition object for the Badge component.
 * @type {object}
 */
export const BadgeDef = {
    name: 'Badge',
    tag: 'rui-badge',

    // ═════════════════════════════════════
    //  Design Tokens
    // ═════════════════════════════════════
    tokens: {
        prefix: 'bd',
        tokens: {
            // Base appearance
            'font-size':    { ref: 'font.size-xs',      description: 'Badge font size' },
            'font-stack':   { ref: 'font.family',        description: 'Font family' },
            'text':         { ref: 'color.text',          description: 'Badge text color' },
            'bg':           { ref: 'color.bg-inset',      description: 'Badge background' },
            'border':       { ref: 'color.border',        description: 'Badge border color' },
            'radius':       { ref: 'radius.full',         description: 'Badge border radius' },
            'px':           { value: '0.5rem',             description: 'Horizontal padding' },
            'py':           { value: '0.125rem',           description: 'Vertical padding' },
            'gap':          { ref: 'spacing.1',           description: 'Gap between dot/icon and text' },
            'min-w':        { value: '1.25rem',            description: 'Minimum width' },

            // Dot indicator
            'dot-size':     { value: '0.5rem',             description: 'Dot indicator size' },
            'dot-bg':       { ref: 'color.accent',         description: 'Dot indicator color' },

            // Size: sm
            'sm-font-size': { value: '0.625rem',           description: 'Small font size' },
            'sm-px':        { value: '0.375rem',           description: 'Small horizontal padding' },
            'sm-py':        { value: '0.0625rem',          description: 'Small vertical padding' },
            'sm-min-w':     { value: '1rem',               description: 'Small minimum width' },

            // Size: lg
            'lg-font-size': { ref: 'font.size-sm',        description: 'Large font size' },
            'lg-px':        { value: '0.75rem',            description: 'Large horizontal padding' },
            'lg-py':        { value: '0.25rem',            description: 'Large vertical padding' },
            'lg-min-w':     { value: '1.5rem',             description: 'Large minimum width' },

            // Variant: success
            'success-bg':      { value: '#dcfce7',         description: 'Success background' },
            'success-text':    { value: '#166534',         description: 'Success text color' },
            'success-border':  { value: '#bbf7d0',         description: 'Success border color' },

            // Variant: warning
            'warning-bg':      { value: '#fef9c3',         description: 'Warning background' },
            'warning-text':    { value: '#854d0e',         description: 'Warning text color' },
            'warning-border':  { value: '#fde68a',         description: 'Warning border color' },

            // Variant: error
            'error-bg':        { value: '#fee2e2',         description: 'Error background' },
            'error-text':      { value: '#991b1b',         description: 'Error text color' },
            'error-border':    { value: '#fecaca',         description: 'Error border color' },

            // Variant: info
            'info-bg':         { value: '#dbeafe',         description: 'Info background' },
            'info-text':       { value: '#1e40af',         description: 'Info text color' },
            'info-border':     { value: '#bfdbfe',         description: 'Info border color' },
        },
    },

    // ═════════════════════════════════════
    //  State Machine
    // ═════════════════════════════════════
    states: {
        initial: 'visible',
        states: {
            visible: { on: { HIDE: 'hidden' } },
            hidden:  { on: { SHOW: 'visible' } },
        },
    },

    // ═════════════════════════════════════
    //  Template Slots
    // ═════════════════════════════════════
    template: {
        slots: {
            root:  { element: 'span',  classes: ['badge'],       role: 'status' },
            dot:   { element: 'span',  classes: ['badge-dot'],   role: null },
            count: { element: 'span',  classes: ['badge-count'], role: null },
            label: { element: 'span',  classes: ['badge-label'], role: null },
        },
    },

    // ═════════════════════════════════════
    //  JIT Parts
    // ═════════════════════════════════════
    jitParts: {
        [PART.ROOT]:    PART.ROOT,
        [PART.DOT]:     PART.DOT,
        [PART.COUNT]:   PART.COUNT,
        [PART.LABEL]:   PART.LABEL,
        [PART.PILL]:    PART.PILL,
        [PART.SM_ROOT]: PART.SM_ROOT,
        [PART.LG_ROOT]: PART.LG_ROOT,
        [PART.SUCCESS]: PART.SUCCESS,
        [PART.WARNING]: PART.WARNING,
        [PART.ERROR]:   PART.ERROR,
        [PART.INFO]:    PART.INFO,
    },

    styles: {},

    // ═════════════════════════════════════
    //  Event Handlers
    // ═════════════════════════════════════
    handlers: {},

    // ═════════════════════════════════════
    //  Variants
    // ═════════════════════════════════════
    variants: {},

    // ═════════════════════════════════════
    //  Custom Element
    // ═════════════════════════════════════
    observedAttrs: ['variant', 'size', 'pill', 'dot', 'count', 'max', 'text', 'hidden'],
    attrMap: {
        variant: 'variant',
        size:    'size',
        pill:    'pill',
        dot:     'dot',
        count:   'count',
        max:     'max',
        text:    'text',
        hidden:  'hidden',
    },
};

export default BadgeDef;
