/**
 * @fileoverview Badge state — state machine transitions + reactive state.
 * @module module/Badge/state
 */

/**
 * Pure state machine transition map for badge visibility.
 */
export const BADGE_TRANSITIONS = {
    initial: 'visible',
    states: {
        visible: { on: { HIDE: 'hidden' } },
        hidden:  { on: { SHOW: 'visible' } },
    },
};

/**
 * Create reactive badge state.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @returns {{ ref: object, setState: Function }}
 */
export function createReactiveState(stateFn) {
    const stateSet = stateFn({
        count: null,
        text: '',
        hidden: false,
    });
    return { ref: stateSet[0], setState: stateSet[1] };
}
